+const FIFTEEN_MINUTES = 15 * 60 * 1000;
+const claims = new Map<string, ClaimSession>();
+
+function buildId(prefix: string) {
+  return `${prefix}-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
+}
+
+export function createClaim(orderId: string, phoneNumber: string) {
+  const now = Date.now();
+  const claim: ClaimSession = {
+    claimId: buildId("claim"),
+    orderId,
+    phoneNumber,
+    status: "waiting_otp",
+    createdAt: now,
+    expiresAt: now + FIFTEEN_MINUTES,
+    deducted: false
+  };
+
+  claims.set(claim.claimId, claim);
+  return { ...claim };
+}
+
+export function getClaim(claimId: string) {
+  const claim = claims.get(claimId);
+  return claim ? { ...claim } : null;
+}
+
+export function markClaimSuccess(claimId: string, otp: string) {
+  const claim = claims.get(claimId);
+  if (!claim) {
+    return null;
+  }
+  claim.status = "success";
+  claim.otp = otp;
+  return { ...claim };
+}
+
+export function markClaimCancelled(claimId: string, reason: "cancelled" | "expired") {
+  const claim = claims.get(claimId);
+  if (!claim) {
+    return null;
+  }
+  if (claim.status === "success") {
+    return { ...claim };
+  }
+  claim.status = reason;
+  return { ...claim };
+}
+
+export function markDeducted(claimId: string) {
+  const claim = claims.get(claimId);
+  if (!claim) {
+    return null;
+  }
