+import { getClaim, markClaimSuccess, markDeducted } from "@/lib/claim-store";
+import { getOtp } from "@/lib/herosms";
+import { deductOrderQuantity } from "@/lib/mock-db";
+import { NextResponse } from "next/server";
+
+export async function POST(request: Request) {
+  const { claimId } = await request.json();
+
+  if (!claimId || typeof claimId !== "string") {
+    return NextResponse.json({ message: "claimId is required." }, { status: 400 });
+  }
+
+  const claim = getClaim(claimId);
+  if (!claim) {
+    return NextResponse.json({ message: "Claim session not found." }, { status: 404 });
+  }
+
+  if (claim.status === "cancelled" || claim.status === "expired") {
+    return NextResponse.json({
+      status: claim.status,
+      otp: null
+    });
+  }
+
+  if (claim.status === "success") {
+    return NextResponse.json({
+      status: "success",
+      otp: claim.otp,
+      quantityDeducted: claim.deducted
+    });
+  }
+
+  const result = await getOtp(claim.phoneNumber);
+  if (!result.otp) {
+    return NextResponse.json({
+      status: "waiting_otp",
+      otp: null
+    });
+  }
+
+  const updatedClaim = markClaimSuccess(claim.claimId, result.otp);
+  if (!updatedClaim) {
+    return NextResponse.json({ message: "Could not update claim." }, { status: 500 });
+  }
+
+  if (!updatedClaim.deducted) {
+    deductOrderQuantity(updatedClaim.orderId);
+    markDeducted(updatedClaim.claimId);
+  }
+
+  return NextResponse.json({
+    status: "success",
+    otp: result.otp,
+    quantityDeducted: true
+  });
+}
