+"use client";
+
+import { AnimatePresence, motion } from "framer-motion";
+import { FormEvent, useEffect, useMemo, useState } from "react";
+import { toast } from "sonner";
+
+type ValidationResponse = {
+  valid: boolean;
+  orderId: string;
+  quantity: number;
+  status: "active" | "depleted";
+  message: string;
+};
+
+type ClaimState = "idle" | "claiming" | "waiting_otp" | "success" | "cancelled" | "expired";
+
+const OTP_POLL_INTERVAL_MS = 5000;
+const CLAIM_DURATION_MS = 15 * 60 * 1000;
+
+export default function HomePage() {
+  const [orderIdInput, setOrderIdInput] = useState("");
+  const [validatedOrder, setValidatedOrder] = useState<ValidationResponse | null>(null);
+  const [isValidating, setIsValidating] = useState(false);
+
+  const [claimState, setClaimState] = useState<ClaimState>("idle");
+  const [claimId, setClaimId] = useState<string | null>(null);
+  const [phoneNumber, setPhoneNumber] = useState<string | null>(null);
+  const [otp, setOtp] = useState<string | null>(null);
+  const [expiresAt, setExpiresAt] = useState<number | null>(null);
+  const [timeLeftMs, setTimeLeftMs] = useState(0);
+
+  const canClaim = !!validatedOrder && validatedOrder.quantity > 0 && claimState !== "claiming";
+
+  const countdownLabel = useMemo(() => {
+    const safeMs = Math.max(timeLeftMs, 0);
+    const totalSeconds = Math.floor(safeMs / 1000);
+    const minutes = Math.floor(totalSeconds / 60)
+      .toString()
+      .padStart(2, "0");
+    const seconds = (totalSeconds % 60).toString().padStart(2, "0");
+    return `${minutes}:${seconds}`;
+  }, [timeLeftMs]);
+
+  async function validateOrder(event: FormEvent) {
+    event.preventDefault();
+    setIsValidating(true);
+
+    try {
+      const response = await fetch("/api/orders/validate", {
+        method: "POST",
+        headers: { "Content-Type": "application/json" },
+        body: JSON.stringify({ orderId: orderIdInput.trim() })
+      });
+      const data = (await response.json()) as ValidationResponse;
+
+      if (!response.ok || !data.valid) {
+        setValidatedOrder(null);
+        toast.error(data.message ?? "Invalid order ID.");
+        return;
+      }
+
+      setValidatedOrder(data);
+      setClaimState("idle");
+      setClaimId(null);
+      setPhoneNumber(null);
+      setOtp(null);
+      setExpiresAt(null);
+      setTimeLeftMs(0);
+      toast.success("Order validated.");
+    } catch {
+      toast.error("Could not validate order. Try again.");
+    } finally {
+      setIsValidating(false);
+    }
+  }
+
+  async function startClaim() {
+    if (!validatedOrder) {
+      return;
+    }
+
+    setClaimState("claiming");
+    setOtp(null);
+
+    try {
+      const response = await fetch("/api/claim/start", {
+        method: "POST",
+        headers: { "Content-Type": "application/json" },
+        body: JSON.stringify({ orderId: validatedOrder.orderId })
+      });
+      const data = await response.json();
+
+      if (!response.ok) {
+        toast.error(data.message ?? "Unable to claim number.");
+        setClaimState("idle");
+        return;
+      }
+
+      setClaimId(data.claimId);
+      setPhoneNumber(data.phoneNumber);
+      setExpiresAt(data.expiresAt ?? Date.now() + CLAIM_DURATION_MS);
